    			child := node{
    				path:      n.path[i:],
    				wildChild: n.wildChild,
    				nType:     static,
    				indices:   n.indices,
    				children:  n.children,
    				handlers:  n.handlers,
    				priority:  n.priority - 1,
    				fullPath:  n.fullPath,
    			}

